fn add(a: i32, b: i32) -> i32 {
    a + b
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn add_works() {
        assert_eq!(5, add(2, 3));
    }

    #[test]
    fn add_negative() {
        assert_eq!(1, add(-2, 3));
    }
}

fn main() {
    println!("2 + 3 = {}", add(2, 3));
}
